// Parse o JSON retornado pelo script
const stdout = $input.item.json.stdout || '';

// Extrai o JSON do output (pode ter texto antes)
const jsonMatch = stdout.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('Script não retornou JSON válido: ' + stdout.substring(0, 200));
}

const analise = JSON.parse(jsonMatch[0]);
const score = analise.fit_titanio_score || 0;

return {
  analise: analise,
  score: score,
  titulo: analise.titulo || 'Edital sem título',
  recomendacao: analise.recomendacao || 'não inscrever',
  valor: analise.valor_max || 0,
  prazo: analise.prazo_inscricao || 'a confirmar',
  produto: analise.produto_recomendado || 'N/A',
  resumo: analise.resumo_executivo || '',
  deve_preencher: score >= 60,
  emoji_score: score >= 70 ? '🟢' : score >= 50 ? '🟡' : '🔴',
};

// Monta mensagem de notificação para score ALTO (>=60)
const d = $('parse-analise').item.json;
const analise = d.analise;

const pontos_fortes = (analise.pontos_fortes || []).slice(0, 3).map(p => `• ${p}`).join('\n');
const docs = (analise.documentos_obrigatorios || []).slice(0, 5).map(d => `• ${d}`).join('\n');

return {
  mensagem: `🎯 *Victor Capital — Novo Edital Aprovado para Inscrição*\n\n` +
    `📋 *${d.titulo}*\n` +
    `${d.emoji_score} Score: ${d.score}/100\n` +
    `💰 Valor: R$ ${d.valor.toLocaleString('pt-BR')}\n` +
    `📅 Prazo: ${d.prazo}\n` +
    `🎯 Produto: ${d.produto}\n\n` +
    `📝 *Resumo:*\n${d.resumo}\n\n` +
    `✅ *Pontos fortes:*\n${pontos_fortes}\n\n` +
    `📎 *Documentos a preparar:*\n${docs}\n\n` +
    `⚠️ *AGUARDANDO APROVAÇÃO DA EQUIPE antes de submeter*\n` +
    `Responda OK para confirmar inscrição ou CANCELAR para arquivar.`,
  subject: `[Victor Capital] Edital aprovado: ${d.titulo}`,
  score: d.score,
  deve_preencher: true,
};

// Monta mensagem de notificação para score BAIXO (<60)
const d = $('parse-analise').item.json;
const analise = d.analise;

const pontos_atencao = (analise.pontos_atencao || []).slice(0, 3).map(p => `• ${p}`).join('\n');

return {
  mensagem: `📊 *Victor Capital — Edital Analisado (Score Baixo)*\n\n` +
    `📋 *${d.titulo}*\n` +
    `🔴 Score: ${d.score}/100 — abaixo do mínimo (60)\n` +
    `💰 Valor: R$ ${d.valor.toLocaleString('pt-BR')}\n` +
    `📅 Prazo: ${d.prazo}\n\n` +
    `📝 *Motivo:*\n${analise.justificativa || ''}\n\n` +
    `⚠️ *Pontos de atenção:*\n${pontos_atencao}\n\n` +
    `❌ *Recomendação: NÃO INSCREVER*\n` +
    `Arquivado no pipeline. Victor continua buscando editais melhores.`,
  subject: `[Victor Capital] Edital arquivado: ${d.titulo}`,
  score: d.score,
  deve_preencher: false,
};

// Merge dos dois caminhos — pega a mensagem disponível
const aprovado = $('montar-msg-aprovado').item?.json;
const reprovado = $('montar-msg-reprovado').item?.json;
return aprovado || reprovado || { mensagem: 'Análise concluída', subject: 'Victor Capital' };

// Salva resultado em arquivo local para auditoria
const fs = require('fs');
const path = require('path');

const pastaAuditoria = '/Volumes/TITA_039/MAC_MINI_03/.openclaw/workspace/projetos/fundos/pipeline/auditoria';
if (!fs.existsSync(pastaAuditoria)) fs.mkdirSync(pastaAuditoria, { recursive: true });

const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
const arquivo = path.join(pastaAuditoria, `n8n_processamento_${timestamp}.json`);

const registro = {
  timestamp: new Date().toISOString(),
  analise: $('parse-analise').item.json.analise,
  mensagem_enviada: $('merge-notificacao').item.json.mensagem,
  status: 'processado',
};

fs.writeFileSync(arquivo, JSON.stringify(registro, null, 2));

return { arquivo_salvo: arquivo, status: 'ok' };
